import{_ as i,c as a,l as e,a as t,t as l,a4 as n,o}from"./chunks/framework.CzsDe1xi.js";const F=JSON.parse('{"title":"Node 详解","description":"","frontmatter":{"title":"Node 详解"},"headers":[],"relativePath":"doc/DevOps/Kubernetes/基础/node.md","filePath":"packages/doc/src/DevOps/Kubernetes/基础/node.md","lastUpdated":1705214817000}'),d={name:"doc/DevOps/Kubernetes/基础/node.md"},r={id:"frontmatter-title",tabindex:"-1"},c=e("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":'Permalink to "{{ $frontmatter.title }}"'},"​",-1),p=n('<p>Node 是 Kubernetes 集群的工作节点，可以是物理机也可以是虚拟机。</p><h2 id="node-的状态" tabindex="-1">Node 的状态 <a class="header-anchor" href="#node-的状态" aria-label="Permalink to &quot;Node 的状态&quot;">​</a></h2><p>Node 包括如下状态信息：</p><ul><li>Address <ul><li>HostName：可以被 kubelet 中的 <code>--hostname-override</code> 参数替代。</li><li>ExternalIP：可以被集群外部路由到的 IP 地址。</li><li>InternalIP：集群内部使用的 IP，集群外部无法访问。</li></ul></li><li>Condition <ul><li>OutOfDisk：磁盘空间不足时为 <code>True</code></li><li>Ready：Node controller 40 秒内没有收到 node 的状态报告为 <code>Unknown</code>，健康为 <code>True</code>，否则为 <code>False</code>。</li><li>MemoryPressure：当 node 有内存压力时为 <code>True</code>，否则为 <code>False</code>。</li><li>DiskPressure：当 node 有磁盘压力时为 <code>True</code>，否则为 <code>False</code>。</li></ul></li><li>Capacity <ul><li>CPU</li><li>内存</li><li>可运行的最大 Pod 个数</li></ul></li><li>Info：节点的一些版本信息，如 OS、kubernetes、docker 等</li></ul><h2 id="node-管理" tabindex="-1">Node 管理 <a class="header-anchor" href="#node-管理" aria-label="Permalink to &quot;Node 管理&quot;">​</a></h2><p>禁止 Pod 调度到该节点上。</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cordon</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">nod</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>驱逐该节点上的所有 Pod。</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> drain</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">nod</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>该命令会删除该节点上的所有 Pod（DaemonSet 除外），在其他 node 上重新启动它们，通常该节点需要维护时使用该命令。直接使用该命令会自动调用<code>kubectl cordon &lt;node&gt;</code>命令。当该节点维护完成，启动了 kubelet 后，再使用<code>kubectl uncordon &lt;node&gt;</code> 即可将该节点添加到 kubernetes 集群中。</p>',10);function h(s,k,u,b,m,g){return o(),a("div",null,[e("h1",r,[t(l(s.$frontmatter.title)+" ",1),c]),p])}const v=i(d,[["render",h]]);export{F as __pageData,v as default};
